local OOllO0OlOl0=165
local OIO0O0l0III=38
local O0lOO0OIIll="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local function OOlIIOlOl0l(d)
    d=(d or ""):gsub("%s+","")
    d=d:gsub("[^"..O0lOO0OIIll.."=]","")
    return (d:gsub(".",function(x)
        if x=="=" then return "" end
        local r,f="",(O0lOO0OIIll:find(x,1,true)-1)
        for i=6,1,-1 do
            r=r..(f%2^i-f%2^(i-1)>0 and "1" or "0")
        end
        return r
    end):gsub("%d%d%d?%d?%d?%d?%d?%d?",function(x)
        if #x~=8 then return "" end
        local c=0
        for i=1,8 do
            if x:sub(i,i)=="1" then c=c+2^(8-i) end
        end
        return string.char(c)
    end))
end
local function OlO0OOIOO0I(a,b)
    local r,m=0,1
    while a>0 or b>0 do
        local aa=a%2
        local bb=b%2
        if aa~=bb then r=r+m end
        a=(a-aa)/2
        b=(b-bb)/2
        m=m*2
    end
    return r
end
local O0IIl0OIOIO=O0OIl0OlOOO:gsub("[^A-Za-z0-9+/=]","")
O0IIl0OIOIO=string.reverse(O0IIl0OIOIO)
local Oll00IOOlI0=OOlIIOlOl0l(O0IIl0OIOIO)
local O0lOOOlIIOI={}
for OOIOOlIll0l=1,#Oll00IOOlI0 do
    local OOI0O00O00I=Oll00IOOlI0:byte(OOIOOlIll0l)
    local O0lII00lOll=(OOI0O00O00I-((OIO0O0l0III+OOIOOlIll0l)%256))%256
    O0lOOOlIIOI[OOIOOlIll0l]=string.char(OlO0OOIOO0I(O0lII00lOll,OOllO0OlOl0))
end
local O0IOO0OlIII=table.concat(O0lOOOlIIOI)
local OOOIO0O00ll=loadstring or load
local O00I0lO0OII,OIllO0lOOOO=OOOIO0O00ll(O0IOO0OlIII)
if not O00I0lO0OII then error(OIllO0lOOOO) end
return O00I0lO0OII()
